const msg = $json.message || {};
const cb = $json.callback_query || {};
const doc = msg?.document || null;

return [{
  json: {
    chat_id: msg?.chat?.id || cb?.message?.chat?.id || null,
    input_text: (msg?.text || '').trim(),
    callback_data: cb?.data || '',
    callback_id: cb?.id || '',
    telegram_file_id: doc?.file_id || '',
    telegram_document_name: doc?.file_name || '',
    telegram_mime_type: doc?.mime_type || '',
    has_document: !!doc
  },
  binary: $binary
}];

const data = $getWorkflowStaticData('global');
const states = data.states || {};
const chatId = String($json.chat_id || 'unknown');
const state = states[chatId] || {};

return [{
  json: {
    ...$json,
    api_base_url: $env.N8N_API_BASE_URL || 'http://host.docker.internal:8000/api',
    rag_base_url: $env.N8N_RAG_BASE_URL || 'http://rag:8001',
    llm_base_url: $env.N8N_LLM_BASE_URL || 'http://llm:8002',
    rag_top_k: Number($env.N8N_RAG_TOP_K || 5),
    active_case_id: state.active_case_id || '',
    pending_action: state.pending_action || ''
  },
  binary: $binary
}];

const text = ($json.input_text || '').trim();
const cb = $json.callback_data || '';
const pending = $json.pending_action || '';
const hasActive = !!$json.active_case_id;
const hasDocument = !!$json.has_document;

let route = 'UNKNOWN';
let selected_case_id = '';
let selected_doc_id = '';

if (text === '/start' || text === '/menu' || cb === 'BACK_MAIN') {
  route = 'START';
} else if (text === '/new_case' || text === '/newcase' || cb === 'MENU_NEW_CASE') {
  route = 'NEW_CASE';
} else if (pending === 'waiting_case_title' && text && !text.startsWith('/')) {
  route = 'SUBMIT_NEW_CASE';
} else if (text === '/list_cases' || text === '/listcases' || cb === 'MENU_LIST_CASES' || cb === 'CASE_LIST') {
  route = 'LIST_CASES';
} else if (cb.startsWith('CASE_SELECT:')) {
  route = 'SELECT_CASE';
  selected_case_id = cb.split(':')[1] || '';
} else if (text.startsWith('/select ')) {
  route = 'SELECT_CASE';
  selected_case_id = text.replace('/select', '').trim();
} else if (text === '/status' || cb === 'CASE_STATUS') {
  route = hasActive ? 'STATUS' : 'NO_ACTIVE_CASE';
} else if (cb === 'CASE_LIST_DOCS') {
  route = hasActive ? 'LIST_DOCS' : 'NO_ACTIVE_CASE';
} else if (cb === 'CASE_DELETE_DOC') {
  route = hasActive ? 'DELETE_DOC' : 'NO_ACTIVE_CASE';
} else if (cb.startsWith('DOC_DELETE:')) {
  route = hasActive ? 'CONFIRM_DELETE_DOC' : 'NO_ACTIVE_CASE';
  selected_doc_id = cb.split(':')[1] || '';
} else if (text === '/add_doc' || text === '/adddoc' || cb === 'CASE_ADD_DOC') {
  route = hasActive ? 'ADD_DOC' : 'NO_ACTIVE_CASE';
} else if (pending === 'waiting_document' && hasDocument) {
  route = hasActive ? 'SUBMIT_ADD_DOC' : 'NO_ACTIVE_CASE';
} else if (text === '/ask' || cb === 'CASE_ASK') {
  route = hasActive ? 'ASK' : 'NO_ACTIVE_CASE';
} else if (pending === 'waiting_question' && text && !text.startsWith('/')) {
  route = hasActive ? 'SUBMIT_ASK' : 'NO_ACTIVE_CASE';
} 

return [{
  json: {
    ...$json,
    route,
    selected_case_id,
    selected_doc_id
  },
  binary: $binary
}];

const data = $getWorkflowStaticData('global');
const states = data.states || {};
const chatId = String($json.chat_id || 'unknown');
states[chatId] = states[chatId] || {};
states[chatId].active_case_id = states[chatId].active_case_id || '';
states[chatId].pending_action = 'waiting_case_title';
data.states = states;
return [{ json: { chat_id: $json.chat_id, message_text: 'Напиши название нового дела одним сообщением', reply_markup_json: JSON.stringify({ inline_keyboard: [[{ text: 'Главное меню', callback_data: 'BACK_MAIN' }]] }) } }];

const resp = $json || {};
const caseId = String(resp.id || resp.case_id || '');
const status = resp.status || 'pending';
const title = $item(0).$node['Determine Route'].json.input_text || 'Без названия';

const data = $getWorkflowStaticData('global');
const states = data.states || {};
const chatId = String($item(0).$node['Load State'].json.chat_id || 'unknown');

states[chatId] = states[chatId] || {};
states[chatId].active_case_id = caseId;
states[chatId].pending_action = '';
states[chatId].cases = Array.isArray(states[chatId].cases) ? states[chatId].cases : [];

const existing = states[chatId].cases.find(c => String(c.case_id || c.id || '') === caseId);
const localCase = {
  case_id: caseId,
  title,
  status,
  chat_id: resp.chat_id || $item(0).$node['Load State'].json.chat_id
};

if (existing) {
  existing.title = localCase.title;
  existing.status = localCase.status;
  existing.chat_id = localCase.chat_id;
} else {
  states[chatId].cases.unshift(localCase);
}

data.states = states;

return [{
  json: {
    chat_id: $item(0).$node['Load State'].json.chat_id,
    case_id: caseId,
    title,
    status,
    message_text: `Дело создано\n\n<b>${title}</b>\nID: <code>${caseId}</code>\nСтатус: ${status}`,
    reply_markup_json: JSON.stringify({
      inline_keyboard: [
        [{ text: 'Статус дела', callback_data: 'CASE_STATUS' }, { text: 'Документы', callback_data: 'CASE_LIST_DOCS' }],
        [{ text: 'Добавить документ', callback_data: 'CASE_ADD_DOC' }, { text: 'Удалить документ', callback_data: 'CASE_DELETE_DOC' }],
        [{ text: 'Спросить по делу', callback_data: 'CASE_ASK' }],
        [{ text: 'Список дел', callback_data: 'CASE_LIST' }, { text: 'Главное меню', callback_data: 'BACK_MAIN' }]
      ]
    })
  }
}];

const payload = $json || {};

let apiCases = [];
if (Array.isArray(payload.cases)) {
  apiCases = payload.cases;
} else if (Array.isArray(payload)) {
  apiCases = payload;
} else if (payload.case_id || payload.id) {
  apiCases = [payload];
}

const data = $getWorkflowStaticData('global');
const states = data.states || {};
const chatId = String($item(0).$node['Load State'].json.chat_id || 'unknown');

states[chatId] = states[chatId] || {};
states[chatId].cases = Array.isArray(states[chatId].cases) ? states[chatId].cases : [];

const localCases = states[chatId].cases;
const mergedCases = apiCases.map(c => {
  const id = String(c.case_id || c.id || '');
  const local = localCases.find(x => String(x.case_id || x.id || '') === id) || {};
  return {
    case_id: id,
    title: c.title || local.title || `Дело ${id}`,
    status: c.status || local.status || 'UNKNOWN',
    documents_count: Number(c.documents_count ?? local.documents_count ?? 0)
  };
}).filter(c => c.case_id);

states[chatId].cases = mergedCases;
data.states = states;

if (!mergedCases.length) {
  return [{
    json: {
      chat_id: $item(0).$node['Load State'].json.chat_id,
      message_text: 'У тебя пока нет дел\n\nНажми кнопку Создать дело',
      reply_markup_json: JSON.stringify({
        inline_keyboard: [
          [{ text: 'Создать дело', callback_data: 'MENU_NEW_CASE' }, { text: 'Главное меню', callback_data: 'BACK_MAIN' }]
        ]
      })
    }
  }];
}

const activeCaseId = String(states[chatId].active_case_id || '');
const rows = mergedCases.map(c => {
  const marker = c.case_id === activeCaseId ? '• ' : '';
  const suffix = c.documents_count ? ` · docs: ${c.documents_count}` : '';
  return [{
    text: `${marker}${c.title} — ${c.status}${suffix}`.slice(0, 60),
    callback_data: `CASE_SELECT:${c.case_id}`
  }];
});

rows.push([{ text: 'Главное меню', callback_data: 'BACK_MAIN' }]);

return [{
  json: {
    chat_id: $item(0).$node['Load State'].json.chat_id,
    message_text: 'Выбери дело',
    reply_markup_json: JSON.stringify({ inline_keyboard: rows })
  }
}];

const data = $getWorkflowStaticData('global');
const states = data.states || {};
const chatId = String($item(0).$node['Load State'].json.chat_id || 'unknown');
const caseId = $item(0).$node['Determine Route'].json.selected_case_id || '';

states[chatId] = states[chatId] || {};
states[chatId].active_case_id = caseId;
states[chatId].pending_action = '';

const cases = Array.isArray(states[chatId].cases) ? states[chatId].cases : [];
const selected = cases.find(c => String(c.case_id || c.id || '') === String(caseId)) || {};
data.states = states;

const title = selected.title || `Дело ${caseId}`;
const status = selected.status || 'UNKNOWN';

return [{
  json: {
    chat_id: $item(0).$node['Load State'].json.chat_id,
    message_text: `Активное дело выбрано\n\n<b>${title}</b>\nID: <code>${caseId}</code>\nСтатус: ${status}`,
    reply_markup_json: JSON.stringify({
      inline_keyboard: [
        [{ text: 'Статус дела', callback_data: 'CASE_STATUS' }, { text: 'Документы', callback_data: 'CASE_LIST_DOCS' }],
        [{ text: 'Добавить документ', callback_data: 'CASE_ADD_DOC' }, { text: 'Удалить документ', callback_data: 'CASE_DELETE_DOC' }],
        [{ text: 'Спросить по делу', callback_data: 'CASE_ASK' }],
        [{ text: 'Список дел', callback_data: 'CASE_LIST' }, { text: 'Главное меню', callback_data: 'BACK_MAIN' }]
      ]
    })
  }
}];

const status = $json.status || $json.case_status || 'UNKNOWN';
const data = $getWorkflowStaticData('global');
const states = data.states || {};
const chatId = String($item(0).$node['Load State'].json.chat_id || 'unknown');
const activeCaseId = String($item(0).$node['Load State'].json.active_case_id || '');
const selected = (states[chatId]?.cases || []).find(c => String(c.case_id || c.id || '') === activeCaseId) || {};
const title = selected.title || `Дело ${activeCaseId}`;

return [{
  json: {
    chat_id: $item(0).$node['Load State'].json.chat_id,
    message_text: `Статус дела\n\n<b>${title}</b>\nID: <code>${activeCaseId}</code>\nСтатус: ${status}`,
    reply_markup_json: JSON.stringify({
      inline_keyboard: [
        [{ text: 'Документы', callback_data: 'CASE_LIST_DOCS' }, { text: 'Добавить документ', callback_data: 'CASE_ADD_DOC' }],
        [{ text: 'Спросить по делу', callback_data: 'CASE_ASK' }],
        [{ text: 'Список дел', callback_data: 'CASE_LIST' }, { text: 'Главное меню', callback_data: 'BACK_MAIN' }]
      ]
    })
  }
}];

const details = $json || {};
const load = $item(0).$node['Load State'].json;
const activeCaseId = String(load.active_case_id || details.case_id || '');
const title = String(details.title || `Дело ${activeCaseId}`);
const status = String(details.status || details.case_status || 'UNKNOWN');
const docs = Array.isArray(details.documents) ? details.documents : [];

const escapeHtml = (value) => String(value || '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;');

if (Number(details.status) === 404 || details.error === 'Not Found') {
  return [{
    json: {
      chat_id: load.chat_id,
      message_text: `Не удалось загрузить документы дела\n\nID: ${escapeHtml(activeCaseId)}\nОшибка API: 404 Not Found`,
      reply_markup_json: JSON.stringify({
        inline_keyboard: [
          [{ text: 'Добавить документ', callback_data: 'CASE_ADD_DOC' }, { text: 'Удалить документ', callback_data: 'CASE_DELETE_DOC' }],
          [{ text: 'Статус дела', callback_data: 'CASE_STATUS' }, { text: 'Список дел', callback_data: 'CASE_LIST' }],
          [{ text: 'Главное меню', callback_data: 'BACK_MAIN' }]
        ]
      })
    }
  }];
}

let docsBlock = 'Документов пока нет.';
if (docs.length) {
  docsBlock = docs.map((doc, index) => {
    const name = escapeHtml(doc.name || doc.filename || `Документ ${index + 1}`);
    const docId = escapeHtml(doc.doc_id || doc.id || `doc_${index + 1}`);
    const pages = doc.pages !== undefined && doc.pages !== null ? `, стр.: ${escapeHtml(doc.pages)}` : '';
    return `${index + 1}. ${name}\nID: ${docId}${pages}`;
  }).join('\n\n');
}

return [{
  json: {
    chat_id: load.chat_id,
    message_text: `Документы дела\n\n<b>${escapeHtml(title)}</b>\nID: ${escapeHtml(activeCaseId)}\nСтатус: ${escapeHtml(status)}\n\n${docsBlock}`,
    reply_markup_json: JSON.stringify({
      inline_keyboard: [
        [{ text: 'Добавить документ', callback_data: 'CASE_ADD_DOC' }, { text: 'Удалить документ', callback_data: 'CASE_DELETE_DOC' }],
        [{ text: 'Статус дела', callback_data: 'CASE_STATUS' }, { text: 'Список дел', callback_data: 'CASE_LIST' }],
        [{ text: 'Главное меню', callback_data: 'BACK_MAIN' }]
      ]
    })
  }
}];

const details = $json || {};
const load = $item(0).$node['Load State'].json;
const activeCaseId = String(load.active_case_id || details.case_id || '');
const title = String(details.title || `Дело ${activeCaseId}`);
const status = String(details.status || details.case_status || 'UNKNOWN');
const docs = Array.isArray(details.documents) ? details.documents : [];

const escapeHtml = (value) => String(value || '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;');

if (Number(details.status) === 404 || details.error === 'Not Found') {
  return [{
    json: {
      chat_id: load.chat_id,
      message_text: `Не удалось загрузить документы для удаления\n\nID: ${escapeHtml(activeCaseId)}\nОшибка API: 404 Not Found`,
      reply_markup_json: JSON.stringify({
        inline_keyboard: [
          [{ text: 'Документы', callback_data: 'CASE_LIST_DOCS' }, { text: 'Статус дела', callback_data: 'CASE_STATUS' }],
          [{ text: 'Главное меню', callback_data: 'BACK_MAIN' }]
        ]
      })
    }
  }];
}

if (!docs.length) {
  return [{
    json: {
      chat_id: load.chat_id,
      message_text: `В деле пока нет документов для удаления\n\n<b>${escapeHtml(title)}</b>\nID: ${escapeHtml(activeCaseId)}\nСтатус: ${escapeHtml(status)}`,
      reply_markup_json: JSON.stringify({
        inline_keyboard: [
          [{ text: 'Добавить документ', callback_data: 'CASE_ADD_DOC' }, { text: 'Документы', callback_data: 'CASE_LIST_DOCS' }],
          [{ text: 'Главное меню', callback_data: 'BACK_MAIN' }]
        ]
      })
    }
  }];
}

const buttons = docs.slice(0, 50).map((doc, index) => {
  const docId = String(doc.doc_id || doc.id || '');
  const name = String(doc.name || doc.filename || `Документ ${index + 1}`);
  return [{
    text: `Удалить: ${name}`.slice(0, 60),
    callback_data: `DOC_DELETE:${docId}`
  }];
});

buttons.push([{ text: 'Документы', callback_data: 'CASE_LIST_DOCS' }, { text: 'Статус дела', callback_data: 'CASE_STATUS' }]);
buttons.push([{ text: 'Главное меню', callback_data: 'BACK_MAIN' }]);

return [{
  json: {
    chat_id: load.chat_id,
    message_text: `Выбери документ для удаления\n\n<b>${escapeHtml(title)}</b>\nID: ${escapeHtml(activeCaseId)}\nСтатус: ${escapeHtml(status)}`,
    reply_markup_json: JSON.stringify({ inline_keyboard: buttons })
  }
}];

const base = $item(0).$node['Load State'].json;
const route = $item(0).$node['Determine Route'].json;
const raw = $json.data ?? (typeof $json === 'string' ? $json : JSON.stringify($json));
let parsed = {};
try { parsed = typeof raw === 'string' ? JSON.parse(raw) : raw; } catch (e) { parsed = {}; }

const data = $getWorkflowStaticData('global');
const states = data.states || {};
const chatId = String(base.chat_id || 'unknown');
states[chatId] = states[chatId] || {};

const selectedDocId = String(route.selected_doc_id || '');
const activeCaseId = String(base.active_case_id || '');
const cases = Array.isArray(states[chatId].cases) ? states[chatId].cases : [];
const selectedCase = cases.find(c => String(c.case_id || c.id || '') === activeCaseId);

const detailsPayload = parsed.case || parsed;
const title = String(detailsPayload.title || selectedCase?.title || `Дело ${activeCaseId}`);
const status = String(detailsPayload.status || detailsPayload.case_status || selectedCase?.status || 'DIRTY');

const ok = !String(raw).toLowerCase().includes('not found') && !String(raw).toLowerCase().includes('error') && !String(raw).toLowerCase().includes('exception');

if (ok) {
  if (selectedCase) {
    selectedCase.status = status;
    if (typeof selectedCase.documents_count === 'number') {
      selectedCase.documents_count = Math.max(0, Number(selectedCase.documents_count) - 1);
    } else {
      selectedCase.documents_count = Math.max(0, Number(selectedCase.documents_count || 1) - 1);
    }
  }
}
data.states = states;

const escapeHtml = (value) => String(value || '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;');

const message_text = ok
  ? `Документ удалён\n\nДело: ${escapeHtml(title)}\nID дела: ${escapeHtml(activeCaseId)}\nID документа: ${escapeHtml(selectedDocId)}\nСтатус дела: ${escapeHtml(status)}`
  : `Не удалось удалить документ\n\nID дела: ${escapeHtml(activeCaseId)}\nID документа: ${escapeHtml(selectedDocId)}\n\nОтвет API:\n<code>${escapeHtml(String(raw).slice(0, 1000))}</code>`;

return [{
  json: {
    chat_id: base.chat_id,
    message_text,
    reply_markup_json: JSON.stringify({
      inline_keyboard: [
        [{ text: 'Документы', callback_data: 'CASE_LIST_DOCS' }, { text: 'Добавить документ', callback_data: 'CASE_ADD_DOC' }],
        [{ text: 'Удалить документ', callback_data: 'CASE_DELETE_DOC' }, { text: 'Статус дела', callback_data: 'CASE_STATUS' }],
        [{ text: 'Список дел', callback_data: 'CASE_LIST' }, { text: 'Главное меню', callback_data: 'BACK_MAIN' }]
      ]
    })
  }
}];

const data = $getWorkflowStaticData('global');
const states = data.states || {};
const chatId = String($json.chat_id || 'unknown');
states[chatId] = states[chatId] || {};
states[chatId].active_case_id = states[chatId].active_case_id || $json.active_case_id || '';
states[chatId].pending_action = 'waiting_document';
data.states = states;
return [{ json: { chat_id: $json.chat_id, message_text: 'Теперь отправь PDF, DOCX или TXT одним сообщением', reply_markup_json: JSON.stringify({ inline_keyboard: [[{ text: 'Документы', callback_data: 'CASE_LIST_DOCS' }, { text: 'Главное меню', callback_data: 'BACK_MAIN' }]] }) } }];

const items = $input.all();
return items.map(item => {
  item.binary = item.binary || {};
  if (item.binary.telegram_file) {
    item.binary.telegram_file.fileName = item.json.telegram_document_name || 'document.bin';
    item.binary.telegram_file.mimeType = item.json.telegram_mime_type || item.binary.telegram_file.mimeType || 'application/octet-stream';
  }
  return item;
});

const buildRaw = $json.data ?? (typeof $json === 'string' ? $json : JSON.stringify($json));
const upload = $item(0).$node['Prepare Build Request'].json;
const uploadOk = !!upload.upload_ok;

const escapeHtml = (value) => String(value || '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;');

const buildLooksBad = (() => {
  const text = String(buildRaw || '').toLowerCase();
  if (!text) return false;
  return text.includes('"detail"') || text.includes('"error"') || text.includes('traceback') || text.includes('exception');
})();

let text;
if (!uploadOk) {
  text = `Не удалось подтвердить загрузку документа\n\nОтвет API:\n<code>${escapeHtml(String(upload.upload_raw || '').slice(0, 700))}</code>`;
} else {
  const buildNote = buildLooksBad
    ? '\n\nДокумент сохранён, но пересборка индекса вернула нестандартный ответ. Проверь RAG сервис.'
    : '\n\nПересборка индекса запущена.';
  text = `Документ загружен\n\nФайл: ${escapeHtml(upload.file_name)}\nДело: ${escapeHtml(upload.active_case_id)}\nID документа: ${escapeHtml(upload.upload_doc_id || 'неизвестно')}${buildNote}`;
}

return [{
  json: {
    chat_id: upload.chat_id,
    message_text: text,
    reply_markup_json: JSON.stringify({
      inline_keyboard: [
        [{ text: 'Документы', callback_data: 'CASE_LIST_DOCS' }, { text: 'Статус дела', callback_data: 'CASE_STATUS' }],
        [{ text: 'Главное меню', callback_data: 'BACK_MAIN' }]
      ]
    })
  }
}];

const data = $getWorkflowStaticData('global');
const states = data.states || {};
const chatId = String($json.chat_id || 'unknown');
states[chatId] = states[chatId] || {};
states[chatId].pending_action = 'waiting_question';
data.states = states;
return [{ json: { chat_id: $json.chat_id, message_text: 'Напиши вопрос по делу одним сообщением', reply_markup_json: JSON.stringify({ inline_keyboard: [[{ text: 'Статус дела', callback_data: 'CASE_STATUS' }, { text: 'Документы', callback_data: 'CASE_LIST_DOCS' }],[{ text: 'Главное меню', callback_data: 'BACK_MAIN' }]] }) } }];

const raw = $json.data ?? (typeof $json === 'string' ? $json : JSON.stringify($json));
let parsed = {};
try { parsed = typeof raw === 'string' ? JSON.parse(raw) : raw; } catch (e) { parsed = {}; }

const retrieve = $item(0).$node['Prepare Generate Request'].json;
const chunksCount = Number(retrieve.chunks_count || 0);
const retrieveRaw = String(retrieve.retrieve_raw || '');

const escapeHtml = (value) => String(value || '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;');

const answer = String(parsed.answer || '').trim();
if (!answer) {
  const reason = chunksCount === 0
    ? 'Не удалось найти релевантные фрагменты по делу'
    : 'Не удалось получить ответ по делу';

  const debugSource = chunksCount === 0 ? retrieveRaw : String(raw);
  return [{
    json: {
      chat_id: $item(0).$node['Load State'].json.chat_id,
      message_text: `${reason}\n\nОтвет сервиса:\n<code>${escapeHtml(debugSource.slice(0, 1000))}</code>`,
      reply_markup_json: JSON.stringify({
        inline_keyboard: [
